// Format: scrape <keywords> <MARKETPLACE> <max>
// Examples:  scrape furniture ES 20
//            scrape power tools DE 50

const msg    = $json.message?.text || '';
const chatId = String($json.message?.chat?.id || '');
const clean  = msg.replace(/^\/?(scrape)\s*/i, '').trim();

const VALID_MP = ['es','de','fr','it','co.uk','com','ca','mx'];
const tokens   = clean.split(/\s+/);

let maxPerKeyword = '50';
let end = tokens.length;
if (end > 0 && /^\d+$/.test(tokens[end - 1])) { maxPerKeyword = tokens[end - 1]; end--; }

let marketplace = 'es';
if (end > 0 && VALID_MP.includes(tokens[end - 1].toLowerCase())) { marketplace = tokens[end - 1].toLowerCase(); end--; }

const keywordRaw = tokens.slice(0, end).join(' ');
const keywords   = keywordRaw.includes(',') ? keywordRaw.split(',').map(k => k.trim()).filter(Boolean).join(',') : keywordRaw.trim();

if (!keywords) throw new Error('Format: scrape <keywords> <marketplace> <max>  e.g.  scrape furniture ES 20');

return [{ json: { keywords, marketplace, maxPerKeyword, chatId } }];

// ── Collect ASINs via Zyte API ───────────────────────────────────────────────
// IMPORTANT: Always returns ≥1 item so downstream nodes always execute.
// If 0 ASINs found, returns a sentinel item with __noAsins:true so the
// pipeline can send a proper Telegram error instead of silently stopping.

const cfg      = $input.first().json;
const key      = cfg.zyteApiKey;
const mp       = cfg.marketplace;
const kwds     = String(cfg.keywords).split(',').map(k => k.trim()).filter(Boolean);
const maxTotal = parseInt(cfg.maxPerKeyword) || 50;

const DOMAINS = { 'es':'amazon.es','de':'amazon.de','fr':'amazon.fr','it':'amazon.it','co.uk':'amazon.co.uk','com':'amazon.com','ca':'amazon.ca','mx':'amazon.com.mx' };
const GEO     = { 'es':'ES','de':'DE','fr':'FR','it':'IT','co.uk':'GB','com':'US','ca':'CA','mx':'MX' };

const dom  = DOMAINS[mp] || 'amazon.es';
const geo  = GEO[mp]     || 'ES';

const authHeader = 'Basic ' + Buffer.from(key + ':').toString('base64');
const seen = new Set();
const out  = [];

for (const kw of kwds) {
  if (out.length >= maxTotal) break;
  const searchUrl = `https://www.${dom}/s?k=${encodeURIComponent(kw)}`;
  console.log(`[ASIN] kw="${kw}"  url=${searchUrl}  collected=${out.length}/${maxTotal}`);

  let foundAsins = [];

  // ── Primary: productList ──
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST', url: 'https://api.zyte.com/v1/extract',
      headers: { 'Authorization': authHeader, 'Content-Type': 'application/json' },
      body: JSON.stringify({ url: searchUrl, productList: true, geolocation: geo }),
    });
    const pl       = resp.productList;
    const products = Array.isArray(pl) ? pl
                   : Array.isArray(pl?.products) ? pl.products
                   : Array.isArray(pl?.items)    ? pl.items
                   : [];
    console.log(`[ASIN] productList: ${products.length} products`);
    for (const p of products) {
      // Try structured ASIN field first
      if (p.asin && /^[A-Z0-9]{10}$/.test(p.asin)) { foundAsins.push(p.asin); continue; }
      // Extract from URL — /dp/ASIN or /gp/product/ASIN
      const urls = [p.url, p.canonicalUrl, p.productUrl].filter(Boolean);
      for (const u of urls) {
        const m = u.match(/\/(?:dp|gp\/product)\/([A-Z0-9]{10})/);
        if (m) { foundAsins.push(m[1]); break; }
      }
    }
    foundAsins = [...new Set(foundAsins)];
    console.log(`[ASIN] productList → ${foundAsins.length} ASINs`);
  } catch (e) { console.warn(`[ASIN] productList failed: ${e.message}`); }

  // ── Fallback: browserHtml ──
  if (foundAsins.length === 0) {
    console.log(`[ASIN] falling back to browserHtml for "${kw}"`);
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST', url: 'https://api.zyte.com/v1/extract',
        headers: { 'Authorization': authHeader, 'Content-Type': 'application/json' },
        body: JSON.stringify({ url: searchUrl, browserHtml: true, geolocation: geo }),
      });
      const html = resp.browserHtml || '';
      console.log(`[ASIN] browserHtml length=${html.length}`);
      const s1 = [...html.matchAll(/data-asin="([A-Z0-9]{10})"/g)].map(m => m[1]);
      const s2 = [...html.matchAll(/\/(?:dp|gp\/product)\/([A-Z0-9]{10})/g)].map(m => m[1]);
      const s3 = [...html.matchAll(/"asin"\s*:\s*"([A-Z0-9]{10})"/g)].map(m => m[1]);
      foundAsins = [...new Set([...s1, ...s2, ...s3])];
      console.log(`[ASIN] browserHtml → s1=${s1.length} s2=${s2.length} s3=${s3.length} unique=${foundAsins.length}`);
    } catch (e) { console.error(`[ASIN] browserHtml failed: ${e.message}`); }
  }

  let cnt = 0;
  for (const asin of foundAsins) {
    if (out.length >= maxTotal) break;
    if (seen.has(asin)) continue;
    seen.add(asin);
    out.push({ asin, keyword: kw, marketplace: mp, scraperUrl: cfg.scraperUrl, scraperApiKey: cfg.scraperApiKey, chatId: cfg.chatId });
    cnt++;
  }
  console.log(`[ASIN] +${cnt} from "${kw}"  total=${out.length}/${maxTotal}`);
}

console.log(`[ASIN] DONE — ${out.length} ASINs`);

// ── CRITICAL: Always return ≥1 item so downstream nodes execute ──
// When 0 ASINs found, return a sentinel so the pipeline can notify via Telegram.
if (out.length === 0) {
  console.warn('[ASIN] 0 ASINs found — returning sentinel for Telegram error notification');
  return [{ json: {
    __noAsins:    true,
    chatId:       cfg.chatId,
    keywords:     kwds.join(', '),
    marketplace:  mp,
    scraperUrl:   cfg.scraperUrl,
    scraperApiKey: cfg.scraperApiKey,
  }}];
}

return out.map(r => ({ json: r }));

// Packs ASINs into batches of 50 for the scraper.
// Handles the __noAsins sentinel from Collect ASINs:
//   → passes through an empty-asins body so the HTTP Request still fires
//   → scraper returns {results:[]} for empty asins (no 400 error)
//   → Parse Response detects __noAsins and sends a Telegram error message.

const items = $input.all();

// ── Sentinel: Collect ASINs found nothing ────────────────────────────────────
if (items.length === 1 && items[0].json.__noAsins) {
  const info = items[0].json;
  console.log(`[BATCH] No ASINs — passing sentinel through`);
  return [{ json: {
    scrapeBody:    { asins: [], marketplace: info.marketplace || 'es' },
    scraperUrl:    info.scraperUrl    || 'http://127.0.0.1:8080',
    scraperApiKey: info.scraperApiKey || '',
    chatId:        info.chatId        || '',
    marketplace:   info.marketplace   || 'es',
    batchIndex:    0,
    totalAsins:    0,
    __noAsins:     true,
    __keywords:    info.keywords      || '',
  }}];
}

const BATCH_SIZE = 50;
const first      = items[0].json;
const mp         = first.marketplace   || 'es';
const scraperUrl = first.scraperUrl    || 'http://127.0.0.1:8080';
const scraperKey = first.scraperApiKey || '';
const chatId     = first.chatId        || '';

console.log(`[BATCH] ${items.length} ASINs → marketplace=${mp}`);

const allAsins = items.map(it => ({
  asin:          it.json.asin,
  category:      it.json.keyword || '',
  category_path: '',
}));

const batches = [];
for (let i = 0; i < allAsins.length; i += BATCH_SIZE) {
  const batch = allAsins.slice(i, i + BATCH_SIZE);
  batches.push({ json: {
    scrapeBody:    { asins: batch, marketplace: mp },
    scraperUrl,
    scraperApiKey: scraperKey,
    chatId,
    marketplace:   mp,
    batchIndex:    batches.length,
    totalAsins:    items.length,
    __noAsins:     false,
  }});
}

console.log(`[BATCH] ${batches.length} batches queued`);
return batches;

// Unpack scraper results → rows for Google Sheets.
// __noAsins sentinel from Batch ASINs → return one error row for Telegram Reply.
// NOTE: no __chatId in output — Telegram Reply reads chatId directly from
//       Parse Telegram Message node, so we don't need to carry it through.

const items     = $input.all();
const scrapedAt = new Date().toISOString();
const allRows   = [];

// ── __noAsins sentinel ───────────────────────────────────────────────────────
const batchMeta = $('2 — Batch ASINs').first().json;
if (batchMeta.__noAsins) {
  const keywords = batchMeta.__keywords || 'unknown';
  const mp       = batchMeta.marketplace || '';
  console.warn(`[PARSE] 0 ASINs found for: ${keywords}`);
  return [{ json: {
    'Status':      'no_asins_found',
    'Keyword':     keywords,
    'Marketplace': mp,
    'Error':       `No products found on Amazon.${mp} for: "${keywords}". Try different keywords.`,
    'Scraped At':  scrapedAt,
    '__noAsins':   true,
  }}];
}

// ── Normal path ──────────────────────────────────────────────────────────────
const mp = batchMeta.marketplace || '';

for (const it of items) {
  let raw = it.json;

  if (typeof raw?.body === 'string') {
    try { raw = JSON.parse(raw.body); } catch(e) { console.error('[PARSE] body parse failed:', e.message); }
  } else if (typeof raw?.data === 'string') {
    try { raw = JSON.parse(raw.data); } catch(e) { console.error('[PARSE] data parse failed:', e.message); }
  } else if (typeof raw === 'string') {
    try { raw = JSON.parse(raw); } catch(e) { console.error('[PARSE] root parse failed:', e.message); }
  }

  console.log(`[PARSE] status=${raw?.status} total=${raw?.total} successful=${raw?.successful}`);
  const results = Array.isArray(raw?.results) ? raw.results : [];
  if (results.length > 0) console.log(`[PARSE] first: ${JSON.stringify(results[0])}`);

  for (const r of results) {
    allRows.push({ json: {
      'ASIN':             r.asin            || '',
      'Keyword':          r.category        || '',
      'Marketplace':      r.marketplace     || mp,
      'Status':           r.status          || '',
      'Business Name':    r.business_name   || '',
      'Email':            r.email           || '',
      'Phone':            r.phone           || '',
      'VAT Number':       r.vat_number      || '',
      'Business Address': r.address         || '',
      'Seller ID':        r.seller_id       || '',
      'Storefront URL':   r.storefront_url  || '',
      'Seller Rating':    r.rating          || '',
      'Error':            r.error           || '',
      'Scraped At':       scrapedAt,
    }});
  }

  if (!results.length && it.json?.error) {
    allRows.push({ json: { 'Status': 'error', 'Error': JSON.stringify(it.json), 'Scraped At': scrapedAt } });
  }
}

console.log(`[PARSE] DONE — ${allRows.length} rows`);
if (!allRows.length) {
  allRows.push({ json: { 'Status': 'no_results', 'Error': 'Scraper returned 0 results', 'Scraped At': scrapedAt } });
}
return allRows;

// Collapse all per-ASIN rows into ONE summary item for a single Telegram message.
const items = $input.all();

if (items.length === 1 && items[0].json.__noAsins) {
  return [{ json: {
    __noAsins:   true,
    keyword:     items[0].json.Keyword     || 'unknown',
    marketplace: items[0].json.Marketplace || '',
  }}];
}

const total   = items.length;
const success = items.filter(r => r.json.Status === 'success').length;
const sold    = items.filter(r => r.json.Status === 'amazon_sold').length;
const errors  = items.filter(r => r.json.Status === 'error').length;
const mp      = items[0]?.json.Marketplace || '';
const kw      = items[0]?.json.Keyword     || '';

return [{ json: { total, success, sold, errors, mp, kw, __noAsins: false } }];

